import (
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// Security limits (best-effort). Otto does not provide a hard sandbox.
const (
	maxScriptBytes  = 8 * 1024
	perItemTimeout  = 25 * time.Millisecond
	maxItemsToCheck = 100000
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if conditionScript == "" {
		return nil, errors.New("conditionScript is empty")
	}
	if len(conditionScript) > maxScriptBytes {
		return nil, fmt.Errorf("conditionScript too large: %d > %d bytes", len(conditionScript), maxScriptBytes)
	}
	if len(items) > maxItemsToCheck {
		return nil, fmt.Errorf("too many items: %d > %d", len(items), maxItemsToCheck)
	}

	// Create one VM and reuse it to avoid repeated initialization and to reduce attack surface.
	vm := otto.New()

	// Remove/disable a few potentially dangerous globals. (Otto isn't Node; still best to minimize.)
	_ = vm.Set("eval", otto.UndefinedValue())
	_ = vm.Set("Function", otto.UndefinedValue())

	// Pre-compile the script once to avoid repeated parsing and to fail fast.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		// Per-item timeout to mitigate infinite loops / heavy computation.
		vm.Interrupt = make(chan func(), 1)
		timer := time.AfterFunc(perItemTimeout, func() {
			select {
			case vm.Interrupt <- func() { panic("script timeout") }:
			default:
			}
		})

		// Inject the current item as a global variable named 'item'
		if err := vm.Set("item", item); err != nil {
			timer.Stop()
			return nil, err
		}

		// Run the condition script with panic recovery (timeout uses panic).
		var runErr error
		value, err := func() (otto.Value, error) {
			defer func() {
				if r := recover(); r != nil {
					runErr = fmt.Errorf("script execution failed: %v", r)
				}
			}()
			return vm.Run(script)
		}()
		timer.Stop()

		if runErr != nil {
			return nil, runErr
		}
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

