package main

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// Security-related limits.
const (
	maxScriptBytes   = 32 * 1024
	perItemTimeout   = 50 * time.Millisecond
	maxItemsToFilter = 100000
)

var (
	ErrScriptTooLarge   = errors.New("condition script too large")
	ErrTooManyItems     = errors.New("too many items")
	ErrScriptTimedOut   = errors.New("script execution timed out")
	ErrInvalidScriptRet = errors.New("script did not evaluate to a boolean/truthy/falsy value")
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security hardening:
//   - Limits script size
//   - Limits number of items
//   - Reuses a single VM and applies a per-item timeout via Otto interrupt
//   - Removes access to common JS-to-host escape vectors (Function/eval) and disables console
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(conditionScript) > maxScriptBytes {
		return nil, ErrScriptTooLarge
	}
	if len(items) > maxItemsToFilter {
		return nil, ErrTooManyItems
	}

	vm := otto.New()

	// Reduce attack surface: remove dynamic code generation and common helpers.
	// Note: Otto doesn't expose Go by default, but disabling these reduces abuse and surprises.
	_, _ = vm.Run(`
		"use strict";
		this.eval = undefined;
		this.Function = undefined;
		this.console = undefined;
	`)

	result := make([]map[string]interface{}, 0, len(items))

	for _, it := range items {
		// Per-item timeout using Otto's interrupt mechanism.
		ctx, cancel := context.WithTimeout(context.Background(), perItemTimeout)

		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		timer := time.AfterFunc(perItemTimeout, func() {
			select {
			case interrupt <- func() { panic(ErrScriptTimedOut) }:
			default:
			}
		})

		// Run safely: convert Otto's interrupt panic into an error.
		ok, runErr := func() (ok bool, err error) {
			defer cancel()
			defer timer.Stop()

			defer func() {
				if r := recover(); r != nil {
					// If the panic value is the sentinel error, return it.
					if e, ok := r.(error); ok && errors.Is(e, ErrScriptTimedOut) {
						err = ErrScriptTimedOut
						return
					}
					// Fallback: string compare.
					if fmt.Sprint(r) == ErrScriptTimedOut.Error() {
						err = ErrScriptTimedOut
						return
					}
					err = fmt.Errorf("script panic: %v", r)
				}
			}()

			// Inject current item as global variable 'item'
			if setErr := vm.Set("item", it); setErr != nil {
				return false, setErr
			}

			// If the context is already done, fail fast.
			select {
			case <-ctx.Done():
				return false, ErrScriptTimedOut
			default:
			}

			val, execErr := vm.Run(conditionScript)
			if execErr != nil {
				return false, execErr
			}

			// Convert result to boolean using JavaScript truthiness
			b, convErr := val.ToBoolean()
			if convErr != nil {
				return false, ErrInvalidScriptRet
			}
			return b, nil
		}()

		if runErr != nil {
			return nil, runErr
		}
		if ok {
			result = append(result, it)
		}
	}

	return result, nil
}

func main() {}

