package main

import (
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// Security limits to reduce risk of untrusted script execution.
const (
	maxScriptBytes = 32 * 1024
	perItemTimeout = 50 * time.Millisecond
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security hardening:
// - Reject overly large scripts.
// - Disable common "escape hatches" (Function/eval) to reduce dynamic code generation.
// - Enforce a per-item execution timeout via Otto's interrupt mechanism to mitigate infinite loops / CPU DoS.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(conditionScript) == 0 {
		return nil, errors.New("condition script is empty")
	}
	if len(conditionScript) > maxScriptBytes {
		return nil, fmt.Errorf("condition script too large: %d bytes (max %d)", len(conditionScript), maxScriptBytes)
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		vm := otto.New()

		// Disable dynamic code generation primitives to reduce attack surface.
		// (Otto doesn't provide a full sandbox; this is best-effort hardening.)
		_ = vm.Set("eval", otto.UndefinedValue())
		_ = vm.Set("Function", otto.UndefinedValue())

		// Per-item timeout to prevent infinite loops / excessive computation.
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt
		timer := time.AfterFunc(perItemTimeout, func() {
			interrupt <- func() {
				panic("script execution timed out")
			}
		})

		// Inject the current item as a global variable named 'item'
		if err := vm.Set("item", item); err != nil {
			timer.Stop()
			return nil, err
		}

		// Run the condition script safely.
		value, runErr := func() (otto.Value, error) {
			var (
				v   otto.Value
				err error
			)
			defer func() {
				// Convert timeout panic into a normal error.
				if r := recover(); r != nil {
					if s, ok := r.(string); ok && s == "script execution timed out" {
						v = otto.Value{}
						err = fmt.Errorf("script execution timed out after %s", perItemTimeout)
						return
					}
					panic(r)
				}
			}()
			v, err = vm.Run(conditionScript)
			return v, err
		}()
		timer.Stop()
		if runErr != nil {
			return nil, runErr
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

func main() {
	// Intentionally empty: library-style function implementation.
}

