// Security hardening:
//   - Reuse a single VM and reset per-iteration state.
//   - Disable common escape hatches (Function/eval) and block access to Go from JS.
//   - Enforce a per-item execution timeout via Otto interrupt.
//   - Validate script size and disallow empty scripts.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
