		maxScriptBytes = 32 * 1024
		perItemTimeout = 50 * time.Millisecond
	)

	if conditionScript == "" {
		return nil, errors.New("conditionScript is empty")
	}
	if len(conditionScript) > maxScriptBytes {
		return nil, errors.New("conditionScript too large")
	}

