		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		timer := time.AfterFunc(perItemTimeout, func() {
			select {
			case interrupt <- func() { panic("script timeout") }:
			default:
			}
		})

		value, err := func() (otto.Value, error) {
			defer func() {
				if r := recover(); r != nil {
					// Normalize timeouts and other panics into errors.
					// (Otto uses panics internally for interrupts.)
				}
