	// Disable dynamic code execution helpers.
	// Note: Otto doesn't provide a full sandbox; this reduces obvious abuse.
	_ = vm.Set("eval", nil)
	_ = vm.Set("Function", nil)

	// Block otto's Go helper if present/added by other code.
	_ = vm.Set("Go", nil)

	// Pre-compile once.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
