package main

import (
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// Security limits to reduce risk of untrusted script execution.
const (
	maxScriptLen   = 8 * 1024
	perItemTimeout = 50 * time.Millisecond
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security hardening:
// - Enforces a maximum script length.
// - Disables common dynamic-eval entry points (eval / Function).
// - Applies a per-item execution timeout via Otto interrupt.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(conditionScript) == 0 {
		return nil, errors.New("condition script is empty")
	}
	if len(conditionScript) > maxScriptLen {
		return nil, fmt.Errorf("condition script too large: %d > %d", len(conditionScript), maxScriptLen)
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, item := range items {
		vm := otto.New()

		// Disable common code-generation primitives.
		// Note: Otto does not provide full sandboxing; this is best-effort hardening.
		_ = vm.Set("eval", func(otto.FunctionCall) otto.Value {
			panic("eval is disabled")
		})
		_ = vm.Set("Function", func(otto.FunctionCall) otto.Value {
			panic("Function constructor is disabled")
		})

		// Per-item timeout using Otto interrupt channel.
		vm.Interrupt = make(chan func(), 1)
		timer := time.AfterFunc(perItemTimeout, func() {
			select {
			case vm.Interrupt <- func() { panic("script timeout") }:
			default:
			}
		})

		// Inject the current item as a global variable named 'item'
		if err := vm.Set("item", item); err != nil {
			timer.Stop()
			return nil, err
		}

		// Run the condition script
		value, runErr := vm.Run(conditionScript)
		timer.Stop()
		if runErr != nil {
			return nil, runErr
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

func main() {
	// Intentionally empty: library-style function.
}

