package main

import (
	"errors"
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

// Security limits for running untrusted JS.
const (
	maxScriptLen = 8 * 1024
	runTimeout   = 50 * time.Millisecond
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security hardening:
//   - Reuses a single VM and compiles the script once (reduces overhead and attack surface).
//   - Enforces a maximum script length.
//   - Enforces a per-item timeout to mitigate infinite loops / long-running scripts.
//   - Removes common host interaction primitives (eval/Function) to reduce script power.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	if len(conditionScript) == 0 {
		return nil, errors.New("conditionScript is empty")
	}
	if len(conditionScript) > maxScriptLen {
		return nil, fmt.Errorf("conditionScript too large: %d > %d", len(conditionScript), maxScriptLen)
	}

	vm := otto.New()

	// Reduce script capabilities a bit. (Otto is not a secure sandbox; this is best-effort hardening.)
	// Remove dynamic code generation helpers.
	_ = vm.Set("eval", otto.UndefinedValue())
	_ = vm.Set("Function", otto.UndefinedValue())

	// Compile once.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	result := make([]map[string]interface{}, 0, len(items))

	for _, it := range items {
		// Per-item timeout to mitigate infinite loops.
		vm.Interrupt = make(chan func(), 1)
		timer := time.AfterFunc(runTimeout, func() {
			select {
			case vm.Interrupt <- func() { panic("script timeout") }:
			default:
			}
		})

		// Ensure timer cleanup and interrupt channel release.
		func() {
			defer timer.Stop()
			defer func() {
				// Convert timeout panic into error.
				if r := recover(); r != nil {
					// Re-panic and handle outside to keep control flow simple.
					panic(r)
				}
			}()

			if err := vm.Set("item", it); err != nil {
				panic(err)
			}

			value, runErr := vm.Run(script)
			if runErr != nil {
				panic(runErr)
			}

			ok, convErr := value.ToBoolean()
			if convErr != nil {
				panic(convErr)
			}

			if ok {
				result = append(result, it)
			}
		}()
	}

	return result, nil
}

func main() {
	// Example usage:
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
	}

	filtered, err := FilterItems(`item.active == true`, items)
	if err != nil {
		panic(err)
	}
	fmt.Println(filtered)
}

