package main

import (
	"fmt"

	"github.com/robertkrimen/otto"
)

// FilterItems evaluates conditionScript once per item using an Otto VM.
// The current item is injected as a global JS variable named `item`.
// If the script evaluates to a truthy value, the item is included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	vm := otto.New()

	// Compile once; run many.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("compile condition script: %w", err)
	}

	out := make([]map[string]interface{}, 0, len(items))

	for i, it := range items {
		if err := vm.Set("item", it); err != nil {
			return nil, fmt.Errorf("set item for index %d: %w", i, err)
		}

		val, err := vm.Run(script)
		if err != nil {
			return nil, fmt.Errorf("run script for index %d: %w", i, err)
		}

		ok, err := val.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("convert result to boolean for index %d: %w", i, err)
		}

		if ok {
			out = append(out, it)
		}
	}

	return out, nil
}

func main() {
	items := []map[string]interface{}{
		{"id": 1, "name": "alice", "age": 17, "active": true},
		{"id": 2, "name": "bob", "age": 21, "active": false},
		{"id": 3, "name": "carol", "age": 30, "active": true},
	}

	// Example: keep only active users age >= 18
	script := `item.active && item.age >= 18`

	filtered, err := FilterItems(script, items)
	if err != nil {
		panic(err)
	}

	fmt.Println("Filtered items:")
	for _, it := range filtered {
		fmt.Printf("%v\n", it)
	}
}

